DELETE FROM workout_set WHERE workout_id IN ( SELECT id FROM workout WHERE user_id = (SELECT id FROM app_user WHERE LOWER(nick) = 'kapiet') ); DELETE FROM workout WHERE user_id = (SELECT id FROM app_user WHERE LOWER(nick) = 'kapiet');
INSERT INTO workout (workout_date, created_by, modified_by, created_on, modified_on, user_id) SELECT DATE '2026-01-06', NULL, NULL, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, u.id FROM app_user u WHERE LOWER(u.nick) = 'kapiet' LIMIT 1;
INSERT INTO workout_set (exercise, repetitions, body_part, weight, line_order, workout_id, status) SELECT v.exercise, v.repetitions, v.body_part, v.weight, v.line_order, w.id, 'DONE' FROM workout w JOIN app_user u ON u.id = w.user_id AND LOWER(u.nick) = 'kapiet' CROSS JOIN (VALUES ('OHP maszyna', 12, 'shoulders', 41.0, 0), ('OHP maszyna', 9, 'shoulders', 41.0, 1), ('OHP maszyna', 5, 'shoulders', 48.0, 2), ('OHP hantle', 10, 'shoulders', 24.0, 3), ('OHP hantle', 10, 'shoulders', 24.0, 4), ('OHP hantle', 10, 'shoulders', 24.0, 5), ('Lateral Raise', 5, 'shoulders', 34.0, 6), ('Lateral Raise', 5, 'shoulders', 34.0, 7), ('Incline Bench Press', 5, 'chest', 40.0, 8), ('Incline Bench Press', 4, 'chest', 40.0, 9), ('Incline Bench Press', 4, 'chest', 40.0, 10) ) AS v(exercise, repetitions, body_part, weight, line_order) WHERE w.workout_date = DATE '2026-01-06';
